// Input validation helpers
function sanitizeAndValidateInvoiceId(id) {
  if (typeof id !== 'string') {
    throw new GraphQLError('Invoice ID must be a string', {
      extensions: { code: 'BAD_USER_INPUT' }
    });
  }

  // Trim whitespace
  const trimmed = id.trim();

  // Validate format: only allow expected invoice ID patterns (e.g., INV-XXX)
  // This prevents injection of unexpected characters
  const invoiceIdPattern = /^[A-Za-z0-9\-]{1,50}$/;
  if (!invoiceIdPattern.test(trimmed)) {
    throw new GraphQLError('Invalid invoice ID format', {
      extensions: { code: 'BAD_USER_INPUT' }
    });
  }

  return trimmed;
}

function validatePaginationParams(limit, offset) {
  const MAX_LIMIT = 100;
  const DEFAULT_LIMIT = 20;

  const validatedLimit = Math.min(
    Math.max(1, Number.isInteger(limit) ? limit : DEFAULT_LIMIT),
    MAX_LIMIT
  );

  const validatedOffset = Math.max(0, Number.isInteger(offset) ? offset : 0);

  return { limit: validatedLimit, offset: validatedOffset };
}

