// Rate limiting simple implementation per user
const rateLimitMap = new Map();
const RATE_LIMIT_WINDOW_MS = 60 * 1000; // 1 minute
const RATE_LIMIT_MAX_REQUESTS = 100;

function rateLimitPlugin() {
  return {
    async requestDidStart(requestContext) {
      return {
        async didResolveOperation(context) {
          const userId = context.contextValue?.user?.id;
          if (!userId) return;

          const now = Date.now();
          const userEntry = rateLimitMap.get(userId);

          if (!userEntry || now - userEntry.windowStart > RATE_LIMIT_WINDOW_MS) {
            rateLimitMap.set(userId, { windowStart: now, count: 1 });
          } else {
            userEntry.count++;
            if (userEntry.count > RATE_LIMIT_MAX_REQUESTS) {
              throw new GraphQLError('Rate limit exceeded. Please try again later.', {
                extensions: { code: 'RATE_LIMITED' }
              });
            }
          }
        }
      };
    }
  };
}

// Custom error formatting to prevent leaking internal details
function formatError(formattedError, error) {
  // Log the full error internally for debugging
  console.error('GraphQL Error:', error);

  // Only return safe error information to the client
  const safeExtensionCodes = [
    'BAD_USER_INPUT',
    'UNAUTHENTICATED',
    'NOT_FOUND',
    'RATE_LIMITED',
    'FORBIDDEN'
  ];

  const code = formattedError.extensions?.code;

  if (safeExtensionCodes.includes(code)) {
    return formattedError;
  }

  // For unexpected errors, return a generic message
  return {
    message: 'An unexpected error occurred',
    extensions: { code: 'INTERNAL_SERVER_ERROR' }
  };
}

